const YOUR_SKILLS = [
  'n8n', 'automation', 'workflow', 'zapier', 'make.com', 'integromat',
  'email automation', 'ai', 'gpt', 'openai', 'claude', 'llm',
  'api integration', 'web scraping', 'python', 'javascript',
  'aws', 'bedrock', 'langchain', 'chatbot', 'data pipeline'
];

const item = $input.first().json;
const text = `${item.jobTitle} ${item.jobDescription} ${item.skillsRequired}`.toLowerCase();

const matchedSkills = YOUR_SKILLS.filter(s => text.includes(s.toLowerCase()));
const matchScore = matchedSkills.length;

if (matchScore < 2) {
  return [];
}

return [{
  json: {
    ...item,
    matchScore,
    matchedSkills
  }
}];

const item = $input.first().json;

const rating = item.clientRating;
const ratingOk = rating === null || rating >= 4.5;

if (!ratingOk) {
  return [];
}

return [{ json: item }];

const input = $input.first().json;

const proposal = input.message?.content 
  || input.text 
  || input.choices?.[0]?.message?.content
  || JSON.stringify(input);

const jobData = $('Filter: Client Rating').first().json;

return [{
  json: {
    ...jobData,
    generatedProposal: proposal
  }
}];

const input = $input.first().json;
const job = input.fields;

let proposal = 'Not available';
try {
  const parsed = JSON.parse(job['AI Proposal']);
  proposal = parsed.output[0].content[0].text;
} catch(e) {
  proposal = job['AI Proposal'] || 'Not available';
}

const message = `🎯 *New Upwork Job Match!*

*${job['Job Title']}*

💰 *Budget:* ${job['Budget'] || 'Not specified'}
📊 *Match Score:* ${job['Match Score']} skills matched
🛠️ *Matched Skills:* ${job['Matched Skills']}
📅 *Posted:* ${job['Posted At']}
📋 *Skills Required:* ${job['Skills Required']}
🔗 *Job Link:* ${job['upwork_url']}

📝 *AI Generated Proposal:*
${proposal}

✅ Saved in Airtable | Job ID: ${job['Job ID']}`;

return [{ json: { ...input, slackMessage: message } }];

const job = $('Filter: Client Rating').first().json;

const userMessage = `Write a proposal for this Upwork job:

JOB TITLE: ${job.jobTitle}

JOB DESCRIPTION:
${job.jobDescription}

BUDGET: ${job.budget}
SKILLS REQUIRED: ${job.skillsRequired}
MATCHED SKILLS: ${Array.isArray(job.matchedSkills) ? job.matchedSkills.join(', ') : (job.matchedSkills || 'Not specified')}

MY PROFILE:
- Name: [YOUR NAME]
- Core Skills: [YOUR SKILLS]
- Experience: [YOUR EXPERIENCE]
- Style: Direct, technical, solution-first. No buzzwords.

Write a tailored proposal that:
1. References a SPECIFIC detail from this exact job post in the opening line
2. Matches my skills precisely to their requirements
3. Proposes a concrete first step or quick win
4. Ends with a clear but soft call-to-action`;

const payload = {
  model: "gpt-4o-mini",
  max_tokens: 600,
  messages: [
    {
      role: "system",
      content: "You are an expert Upwork freelancer proposal writer. You write concise, personalized, high-converting proposals that directly address the client's needs. Never use generic templates. Always: (1) Open with a line proving you read the job post carefully, (2) Demonstrate specific relevant experience with real numbers, (3) Propose a clear approach or solution, (4) End with a soft call-to-action. Keep proposals between 150-250 words. No filler words, no fluff."
    },
    {
      role: "user",
      content: userMessage
    }
  ]
};

return [{
  json: {
    ...job,
    openAiPayload: payload
  }
}];

const item = $input.item.json;

function extractUpworkUrl(vollnaUrl) {
  try {
    const split = vollnaUrl.split('url=');
    if (split.length < 2) return 'no url param found';
    const raw = split[1];
    const step1 = raw.replace(/%25/g, '%');
    const step2 = decodeURIComponent(step1);
    return step2;
  } catch(e) {
    return 'decode error: ' + e.message;
  }
}

function extractBudget(text) {
  if (!text) return 'Not specified';
  const fixed = text.match(/Budget:\s*\$?([\d,]+)/i);
  const hourly = text.match(/\$([\d.]+)\s*\/hr/i);
  if (fixed) return `Fixed: $${fixed[1]}`;
  if (hourly) return `Hourly: $${hourly[1]}/hr`;
  return 'Not specified';
}

function extractSkills(text) {
  if (!text) return '';
  const match = text.match(/Skills:\s*([^\n<]+)/i);
  return match ? match[1].trim() : '';
}

function extractClientRating(text) {
  if (!text) return null;
  const match = text.match(/([\d.]+)\s*of\s*5/i) || text.match(/Rating:\s*([\d.]+)/i);
  return match ? parseFloat(match[1]) : null;
}

function extractClientSpent(text) {
  if (!text) return null;
  const match = text.match(/\$([\d,]+)\+?\s*spent/i) || text.match(/\$([\d,]+)\+?\s*total spent/i);
  return match ? match[1].replace(/,/g, '') : null;
}

function generateJobId(url) {
  const match = url?.match(/~([a-zA-Z0-9]+)/);
  return match ? match[1] : url;
}

const description = item.contentSnippet || item.content || item.summary || '';
const guid = item.guid || item.link || '';

return [{
  json: {
    jobTitle: item.title || 'Untitled',
    jobUrl: item.link || item.url || '',
    jobDescription: description,
    postedAt: item.pubDate || item.isoDate || new Date().toISOString(),
    budget: extractBudget(description),
    skillsRequired: extractSkills(description),
    clientRating: extractClientRating(description),
    clientSpent: extractClientSpent(description),
    jobId: generateJobId(item.link || item.url || guid),
    rawGuid: guid,
    upworkUrl: extractUpworkUrl(guid)
  }
}];
